#include <stdio.h>
#include <stdlib.h>
#define K 22.0 / 7.0

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int compareRubber(const void *a, const void *b) {
    int* x = (int*)a;
    int* y = (int*)b;
    return x[0] - y[0];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int boxes[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &boxes[i]);
        }
        qsort(boxes, N, sizeof(int), compare);
        int M;
        scanf("%d", &M);
        int rubberBands[M][2];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &rubberBands[i][0], &rubberBands[i][1]);
        }
        qsort(rubberBands, M, sizeof(int) * 2, compareRubber);
        int packed = 0;
        int j = 0;
        for (int i = 0; i < N; i++) {
            while (j < M) {
                if (2 * K * rubberBands[j][0] <= 4 * boxes[i] && 4 * boxes[i] <= 2 * K * rubberBands[j][1]) {
                    packed++;
                    j++;
                    break;
                }
                j++;
            }
        }
        printf("%d\n", packed);
    }
    return 0;
}

