import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] boxes = new int[N];
            for (int i = 0; i < N; i++) {
                boxes[i] = sc.nextInt();
            }
            Arrays.sort(boxes);
            int M = sc.nextInt();
            int[][] rubberBands = new int[M][2];
            for (int i = 0; i < M; i++) {
                rubberBands[i][0] = sc.nextInt();
                rubberBands[i][1] = sc.nextInt();
            }
            Arrays.sort(rubberBands, (a, b) -> a[0] - b[0]);
            int packed = 0;
            int j = 0;
            for (int i = 0; i < N; i++) {
                while (j < M) {
                    if (2 * Math.PI * rubberBands[j][0] <= 4 * boxes[i] && 4 * boxes[i] <= 2 * Math.PI * rubberBands[j][1]) {
                        packed++;
                        j++;
                        break;
                    }
                    j++;
                }
            }
            System.out.println(packed);
        }
    }
}

